steps.solution:
projects = [
    {"name": "founder vision reel",   "team_familiarity_react": True,  "needs_text_reflow": False, "render_target": "local", "complexity": "simple"},
    {"name": "spotify wrapped clone", "team_familiarity_react": True,  "needs_text_reflow": False, "render_target": "scale", "complexity": "high"},
    {"name": "brand kit promo",       "team_familiarity_react": False, "needs_text_reflow": False, "render_target": "local", "complexity": "medium"},
    {"name": "multilingual product",  "team_familiarity_react": True,  "needs_text_reflow": True,  "render_target": "local", "complexity": "medium"},
    {"name": "agency in-house team",  "team_familiarity_react": True,  "needs_text_reflow": False, "render_target": "local", "complexity": "high"},
]

def pick(p):
    if p["complexity"] == "simple" and p["render_target"] == "local":
        return "ai-gen-only"
    if p["team_familiarity_react"] and p["render_target"] == "scale":
        return "remotion"
    if p["needs_text_reflow"] or not p["team_familiarity_react"]:
        return "hyperframes"
    return "both"

def route_projects(projects):
    return {p["name"]: pick(p) for p in projects}

out = route_projects(projects)
for p in projects:
    print(f"{p['name']+':':24s}{out[p['name']]}")

